import{_ as a,c as n,a1 as e,o as i}from"./chunks/framework.BDxlaA_J.js";const k=JSON.parse('{"title":"Enumerating Services","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/3-enumeration/1-Enumerating-with-Nmap.md","filePath":"categories/ethical-hacking-labs/3-enumeration/1-Enumerating-with-Nmap.md"}'),t={name:"categories/ethical-hacking-labs/3-enumeration/1-Enumerating-with-Nmap.md"};function p(l,s,o,r,h,c){return i(),n("div",null,s[0]||(s[0]=[e(`<h1 id="enumerating-services" tabindex="-1">Enumerating Services <a class="header-anchor" href="#enumerating-services" aria-label="Permalink to &quot;Enumerating Services&quot;">​</a></h1><p>Extracting user names, machine names, network resources, shares, and services from a system.</p><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>Scan all the machines on a given network or subnet.</li><li>List all alive hosts.</li><li>Determine open ports on a given node.</li><li>Find if any port has firewall restriction.</li><li>Enumerate all the services running on the port along with their respective versions.</li></ul><h3 id="requisites" tabindex="-1">Requisites: <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites:&quot;">​</a></h3><ul><li>Windows Server 2012 or 2016 machine.</li><li>Kali Linux machine.</li><li>Another version of Windows (7, 8, 10 or Server).</li></ul><h2 id="ping-sweep-nmap" tabindex="-1">Ping Sweep - <code>Nmap</code> <a class="header-anchor" href="#ping-sweep-nmap" aria-label="Permalink to &quot;Ping Sweep - \`Nmap\`&quot;">​</a></h2><p>You can perform a ping sweep in Nmap by using ping scan only (<code>-sP</code>) on the whole subnet.</p><p>The ping sweep on Nmap will scan all the nodes on the subnet and starts displaying all the hosts that are up and running, along with their respective MAC Addresses and device information.</p><p>Open a new Terminal window on your Kali Linux and type::</p><p><code>nmap -sP 10.0.2.1/24</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.1</span></span>
<span class="line"><span>Host is up (0.0011s latency).</span></span>
<span class="line"><span>MAC Address: 22:44:99:33:11:55 QEMU virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.2</span></span>
<span class="line"><span>Host is up (0.00084s latency).</span></span>
<span class="line"><span>MAC Address: 22:44:99:33:11:55 (QEMU virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.3</span></span>
<span class="line"><span>Host is up (0.00097s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.22</span></span>
<span class="line"><span>Host is up (0.00075s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00066s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.37</span></span>
<span class="line"><span>Host is up (0.00051s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.15</span></span>
<span class="line"><span>Host is up.</span></span>
<span class="line"><span>Nmap done: 256 IP addresses (7 hosts up) scanned in 2.29 seconds</span></span></code></pre></div><h2 id="ping-sweep-bash" tabindex="-1">Ping Sweep - <code>Bash</code> <a class="header-anchor" href="#ping-sweep-bash" aria-label="Permalink to &quot;Ping Sweep - \`Bash\`&quot;">​</a></h2><p>I will show another way to check live hosts on the subnet with a little bit of <strong>Bash scripting</strong>. You can scroll to the next section if you are not interested.</p><h3 id="_1-test-the-one-liner-command-to-grab-only-ip-addresses" tabindex="-1">1. Test the one-liner command to grab only IP addresses <a class="header-anchor" href="#_1-test-the-one-liner-command-to-grab-only-ip-addresses" aria-label="Permalink to &quot;1. Test the one-liner command to grab only IP addresses&quot;">​</a></h3><p>First of, I will use the <code>ping</code> command on a given subnet range, to check if the hosts are alive. <strong>The goal is: ping every single host on a given range with a clean output for it.</strong></p><p>The clean output part is because when we use <code>ping</code> command, they return a bunch of strings, the goal is remove all the unnecessary information and stick only to the IP addresses. <strong>Example:</strong></p><p><code>ping -c 1 8.8.8.8</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PING 8.8.8.8 (8.8.8.8) 56(84) bytes of data.</span></span>
<span class="line"><span>64 bytes from 8.8.8.8: icmp_seq=2 ttl=54 time=155 ms</span></span>
<span class="line"><span>--- 8.8.8.8 ping statistics ---</span></span>
<span class="line"><span>1 packets transmitted, 0 received, 100% packet loss, time 0ms</span></span></code></pre></div><p>We only need the second line of this output starting with <strong>&quot;64 bytes(...)&quot;</strong> that have the IP address of the alive host.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>64 bytes from 8.8.8.8: icmp_seq=2 ttl=54 time=155 m</span></span></code></pre></div><p><strong>Grabbing only IP addresses:</strong></p><p><code>ping -c 5 8.8.8.8 | grep &quot;64&quot; | cut -d &quot; &quot; -f 4 | tr -d &quot;:&quot; ; &gt; iptest.txt</code></p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span></code></pre></div><p>Breaking down the one-liner command (by pipe):</p><ol><li>Ping the IP 5 times;</li><li>Grep the first string characters of the line (<strong>64</strong> bytes...);</li><li>Cut the whitespaces on 4 slices to reach the IP string;</li><li>Use translate command to trim/delete the &quot;:&quot; symbol;</li><li>Export the results to a .txt file;</li></ol><h3 id="_2-transforming-into-script" tabindex="-1">2. Transforming into script <a class="header-anchor" href="#_2-transforming-into-script" aria-label="Permalink to &quot;2. Transforming into script&quot;">​</a></h3><ol><li>Create a file .sh (pingsweep.sh)</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/bash </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[-] You forgot the IP address!&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[-] Syntax: ./ipsweep.sh 10.10.10&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ip </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> \`</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">seq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 254</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> $1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ip </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;64 bytes&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot; &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">done</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p>Is more convenient to take the user&#39;s input on the first three octets and the last octet is the loop (1 - 254). <strong>Input example: 192.168.1</strong></p><p>The script below is very barebone, have one conditional statement for grab the correct user&#39;s input, a loop through the subnet range, and the one-liner command using the user&#39;s input with the loop variable.</p><ol start="2"><li>Save the file, change the permissions and make executable:</li></ol><p><code>chmod 770 pingsweep.sh</code><code>chmod +x pingsweep.sh</code></p><ol start="3"><li>Test it out:</li></ol><p><code>./pingsweep.sh 10.0.2 &gt; ping-results.txt</code><code>cat ping-results.txt</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.0.2.3</span></span>
<span class="line"><span>10.0.2.1</span></span>
<span class="line"><span>10.0.2.15</span></span>
<span class="line"><span>10.0.2.22</span></span>
<span class="line"><span>10.0.2.23</span></span>
<span class="line"><span>10.0.2.37</span></span></code></pre></div><h2 id="perform-stealth-syn-scan" tabindex="-1">Perform Stealth Syn Scan <a class="header-anchor" href="#perform-stealth-syn-scan" aria-label="Permalink to &quot;Perform Stealth Syn Scan&quot;">​</a></h2><p>Now, choose and IP address from the results, and perform a <strong>stealthy syn scan</strong> on <strong>Nmap</strong>.</p><p><code>nmap -sS &lt;Target IP Address&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...</span></span>
<span class="line"><span>Host is up (0.00092s latency).</span></span>
<span class="line"><span>Not shown: 977 closed ports</span></span>
<span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>53/tcp    open  domain</span></span>
<span class="line"><span>80/tcp    open  http</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap</span></span>
<span class="line"><span>443/tcp   open  https</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>SYN scan is the default and most popular scan option for good reason. It can be performed quickly, scanning thousands of ports per second on a fast network not hampered by intrusive firewalls.</p><h2 id="stealth-syn-scan-with-version-and-os-detection" tabindex="-1">Stealth Syn Scan with Version and OS Detection <a class="header-anchor" href="#stealth-syn-scan-with-version-and-os-detection" aria-label="Permalink to &quot;Stealth Syn Scan with Version and OS Detection&quot;">​</a></h2><p>Version Detection collects information about the specific service running on an open port, including the product name and version number. This information can be critical in determining an entry point for an attack</p><p>Nmap will perform a stealth scan with version detection along with OS detection.</p><p><code>nmap -sSV -O &lt;Target IP Address&gt; -oN Enumeration.txt</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host is up (0.0017s latency).</span></span>
<span class="line"><span>Not shown: 977 closed ports</span></span>
<span class="line"><span>PORT      STATE SERVICE            VERSION</span></span>
<span class="line"><span>53/tcp    open  domain?</span></span>
<span class="line"><span>80/tcp    open  http               Microsoft IIS httpd 8.5</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec       Microsoft Windows Kerberos (server time: 2019-12-06 20:56:57Z)</span></span>
<span class="line"><span>135/tcp   open  msrpc              Microsoft Windows RPC</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn        Microsoft Windows netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap               Microsoft Windows Active Directory LDAP (Domain: Lab.local, Site: Default-First-Site-Name)</span></span>
<span class="line"><span>443/tcp   open  ssl/https?</span></span></code></pre></div><p>The <code>-oN</code> stands for output / export the results into a text file that will save in your home /root/ directory with name <code>Enumeration.txt</code>.</p><hr><h3 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h3><p>By performing services enumeration, an attacker might attempt to find vulnerabilities associated with that particular application and exploit them to gain access to the target machine.</p>`,50)]))}const g=a(t,[["render",p]]);export{k as __pageData,g as default};
